return [
  {
    json: {
      search_queries: [
        'GTM engineer',
        'AI governance analyst'
      ],
      lookback_days: 7,
      prompt_version: 'marketlens-v1',
      schema_version: '2026-05-05',
      model_name: 'gpt-4o-mini'
    }
  }
];

const job = $json;
const company = (job.company_name || job.company || '').trim();
const title = (job.title || '').trim();
const description = (job.description || job.detected_extensions?.description || '').trim();
const externalJobId = job.job_id || job.share_link || `${title}_${company}`;

if (!company || !title || !description) {
  return [{
    json: {
      ...job,
      external_job_id: externalJobId,
      company_name: company,
      job_title: title,
      raw_description: description,
      validation_status: 'missing_required_input',
      error_message: 'Missing company, title, or description before enrichment.'
    }
  }];
}

return [{
  json: {
    external_job_id: externalJobId,
    company_name: company,
    job_title: title,
    raw_description: description,
    job_url: job.share_link || job.link || job.apply_options?.[0]?.link || '',
    posted_at: job.detected_extensions?.posted_at || job.extensions?.join(', ') || '',
    source_query: $('Split Queries').item.json.search_queries,
    prompt_version: $('MarketLens Query Config').first().json.prompt_version,
    schema_version: $('MarketLens Query Config').first().json.schema_version,
    model_name: $('MarketLens Query Config').first().json.model_name,
    validation_status: 'ready'
  }
}];

const source = $('Build Labor Market Prompt').item.json;
const raw = $json.output || $json.text || $json.message?.content || JSON.stringify($json);

function fail(status, message) {
  return [{
    json: {
      ...source,
      enrichment: null,
      raw_model_output: raw,
      validation_status: status,
      error_message: message
    }
  }];
}

let parsed;
try {
  parsed = typeof raw === 'string' ? JSON.parse(raw) : raw;
} catch (error) {
  return fail('invalid_json', error.message);
}

const required = ['role_title_normalized', 'role_family', 'role_cluster', 'emerging_role_score', 'ai_relevance_score', 'automation_relevance_score', 'company_type', 'seniority', 'confidence_score'];
for (const field of required) {
  if (parsed[field] === undefined || parsed[field] === null || String(parsed[field]).trim() === '') {
    return fail('schema_error', `Missing required enrichment field: ${field}`);
  }
}

const scoreFields = ['emerging_role_score', 'ai_relevance_score', 'automation_relevance_score'];
for (const field of scoreFields) {
  const value = Number(parsed[field]);
  if (!Number.isFinite(value) || value < 1 || value > 10) {
    return fail('schema_error', `Score out of range: ${field}`);
  }
  parsed[field] = Math.round(value);
}

parsed.confidence_score = Number(parsed.confidence_score);
if (!Number.isFinite(parsed.confidence_score) || parsed.confidence_score < 0 || parsed.confidence_score > 1) {
  return fail('schema_error', 'confidence_score out of range');
}

const arrayFields = ['tools', 'technical_skills', 'business_skills', 'ai_skills', 'responsibilities', 'less_differentiating_alone_signals', 'evidence_snippets'];
for (const field of arrayFields) {
  parsed[field] = Array.isArray(parsed[field]) ? [...new Set(parsed[field].filter(Boolean).map((item) => String(item).trim()))] : [];
}

return [{
  json: {
    ...source,
    enrichment: parsed,
    raw_model_output: parsed,
    validation_status: parsed.confidence_score < 0.55 ? 'low_confidence' : 'valid',
    error_message: null
  }
}];
